    _CLOCK_GEN = _strip(4, """
      {prefix}clk_proc: process is
        variable seed1              : positive := {seed};
        variable seed2              : positive := 1;
        variable rand               : real;
      begin
        {prefix}clk <= '1';
        wait for 5 ns;
        for i in 1 to {timeout} loop
          -- Simulate clock jitter on the rising edge of the clock. This
