    2 => out_data'length,
    1 => out_count'length,
    0 => 1 -- out_last
  ));

  signal outD_sData             : std_logic_vector(IOI(IOI'high)-1 downto 0);
  signal out_sData              : std_logic_vector(IOI(IOI'high)-1 downto 0);

